    await _addQuiz('itil-v4', 'module-1', [
      {'order': 1, 'question': 'What is the primary purpose of ITIL V4?', 'options': ['To replace all IT staff with automation', 'To provide best practice guidance for IT service management', 'To define programming languages used in IT', 'To regulate software licensing'], 'correctIndex': 1, 'explanation': 'ITIL V4 provides organisations with best practice guidance to plan, deliver, and improve IT services.'},
      {'order': 2, 'question': 'What does ITSM stand for?', 'options': ['International Technology Standards Management', 'IT Service Management', 'Integrated Technology Systems Model', 'IT Security Monitoring'], 'correctIndex': 1, 'explanation': 'ITSM stands for IT Service Management — the practice of managing IT services to meet business needs.'},
      {'order': 3, 'question': 'Which of the following best describes a service in ITIL V4?', 'options': ['A piece of software installed on a server', 'A means of enabling value co-creation by facilitating desired outcomes', 'A contract between a provider and customer', 'A helpdesk ticket system'], 'correctIndex': 1, 'explanation': 'A service enables value co-creation by helping customers achieve outcomes without managing specific costs and risks.'},
      {'order': 4, 'question': 'How does ITIL V4 differ from ITIL V3?', 'options': ['ITIL V4 uses more rigid processes', 'ITIL V4 removes all service management principles', 'ITIL V4 adopts a more holistic value-driven approach aligned with Agile and DevOps', 'ITIL V4 only applies to cloud environments'], 'correctIndex': 2, 'explanation': 'ITIL V4 evolved from V3 by becoming more holistic and aligning with modern methods like Agile, DevOps and Lean.'},
      {'order': 5, 'question': 'In ITIL V4, who creates value?', 'options': ['Only the service provider', 'Only the customer', 'Value is co-created between provider and consumer', 'The IT department alone'], 'correctIndex': 2, 'explanation': 'Value is always co-created — both the provider and the consumer must participate for value to be realised.'},
      {'order': 6, 'question': 'Which of the following is a key stakeholder in ITIL V4?', 'options': ['Only IT engineers', 'Only the CEO', 'Service providers, consumers, partners, suppliers and regulators', 'Only paying customers'], 'correctIndex': 2, 'explanation': 'ITIL V4 recognises a broad set of stakeholders including providers, consumers, partners, suppliers and regulators.'},
    ]);

