    // MODULE 5 - Guiding Principles
    await _addFlashcards('itil-v4', 'module-5', [
      {'order': 1, 'question': 'What are the seven guiding principles of ITIL V4?', 'answer': 'The seven guiding principles are: 1) Focus on value, 2) Start where you are, 3) Progress iteratively with feedback, 4) Collaborate and promote visibility, 5) Think and work holistically, 6) Keep it simple and practical, 7) Optimise and automate.', 'example': 'These principles act as universal guidelines — they apply to every decision, improvement initiative, and service interaction regardless of the situation.'},
      {'order': 2, 'question': 'What does Focus on Value mean?', 'answer': 'Everything the organisation does must link directly or indirectly back to value for stakeholders. Teams should always ask how their work benefits the customer and the business — eliminating activities that do not contribute to value.', 'example': 'Before adding a new approval step to a process, ask: does this step add value for the customer or just create delay?'},
      {'order': 3, 'question': 'What does Start Where You Are mean?', 'answer': 'Do not discard existing services, processes, or tools without first assessing their current value. Build on what already works rather than starting from scratch unnecessarily — this reduces waste, cost, and disruption.', 'example': 'Before replacing a legacy CRM system, evaluate which features staff actually use and whether a migration is truly needed.'},
      {'order': 4, 'question': 'What does Progress Iteratively with Feedback mean?', 'answer': 'Break work into smaller manageable iterations rather than attempting large, risky transformations. Gather feedback after each iteration to learn, adapt, and improve before moving forward.', 'example': 'Instead of deploying a completely new IT platform in one go, release it in phases — test, gather feedback, improve, then release the next phase.'},
      {'order': 5, 'question': 'What does Think and Work Holistically mean?', 'answer': 'No service, practice, or process operates in isolation. To deliver value, teams must understand how all parts of the organisation connect and impact each other — considering the whole system rather than just individual components.', 'example': 'When changing the incident management process, consider how it affects service requests, change management, and customer communication — not just the helpdesk team.'},
      {'order': 6, 'question': 'What does Optimise and Automate mean?', 'answer': 'Maximise the value of human and technical resources by removing unnecessary steps and automating repetitive tasks where possible. Automation frees up people for complex, creative, or high-value work.', 'example': 'Automating password resets frees up helpdesk staff to focus on complex incidents that genuinely require human expertise.'},
    ]);

    await _addQuiz('itil-v4', 'module-5', [
      {'order': 1, 'question': 'How many guiding principles does ITIL V4 have?', 'options': ['4', '5', '6', '7'], 'correctIndex': 3, 'explanation': 'ITIL V4 has seven guiding principles that provide universal guidance for decisions and actions.'},
      {'order': 2, 'question': 'Which principle encourages building on existing work rather than starting from scratch?', 'options': ['Focus on value', 'Start where you are', 'Keep it simple and practical', 'Optimise and automate'], 'correctIndex': 1, 'explanation': 'Start Where You Are encourages assessing current services and building on what works rather than discarding everything.'},
      {'order': 3, 'question': 'Which principle promotes releasing work in phases and gathering feedback?', 'options': ['Think and work holistically', 'Collaborate and promote visibility', 'Progress iteratively with feedback', 'Focus on value'], 'correctIndex': 2, 'explanation': 'Progress Iteratively with Feedback means working in smaller iterations and using feedback to improve before the next step.'},
      {'order': 4, 'question': 'What does Think and Work Holistically mean?', 'options': ['Focus only on the IT team\'s work', 'Consider how all parts of the organisation connect and impact each other', 'Automate as many tasks as possible', 'Keep all processes simple'], 'correctIndex': 1, 'explanation': 'Thinking and working holistically means understanding how all components of the system interact to deliver value.'},
      {'order': 5, 'question': 'Which principle encourages removing unnecessary steps and using automation?', 'options': ['Focus on value', 'Start where you are', 'Keep it simple and practical', 'Optimise and automate'], 'correctIndex': 3, 'explanation': 'Optimise and Automate focuses on maximising efficiency by removing waste and automating repetitive tasks.'},
      {'order': 6, 'question': 'Why is Focus on Value the first guiding principle?', 'options': ['Because it was written first', 'Because all other principles and activities ultimately serve the purpose of delivering value', 'Because it is the easiest to implement', 'Because it only applies to senior management'], 'correctIndex': 1, 'explanation': 'Focus on Value is foundational — every action, principle, and practice in ITIL ultimately exists to deliver value to stakeholders.'},
    ]);

    // MODULE 6 - ITIL Practices
    await _addFlashcards('itil-v4', 'module-6', [
      {'order': 1, 'question': 'What is an ITIL practice?', 'answer': 'A practice is a set of organisational resources designed for performing work or accomplishing an objective. ITIL V4 defines 34 practices grouped into three categories: General Management, Service Management, and Technical Management practices.', 'example': 'Incident Management is a service management practice — it defines how to handle disruptions and restore service as quickly as possible.'},
      {'order': 2, 'question': 'What is the Incident Management practice?', 'answer': 'Incident Management aims to minimise the negative impact of incidents by restoring normal service operation as quickly as possible. An incident is an unplanned interruption or reduction in quality of an IT service.', 'example': 'When a company\'s email server goes down, incident management kicks in: log the incident, diagnose, escalate if needed, fix, and restore service.'},
      {'order': 3, 'question': 'What is the Change Enablement practice?', 'answer': 'Change Enablement maximises the number of successful changes by ensuring risks are properly assessed, authorised, and managed. It distinguishes between standard, normal, and emergency changes based on risk and urgency.', 'example': 'Upgrading a core banking system requires a normal change — risk assessment, approval, testing, and a rollback plan before going live.'},
      {'order': 4, 'question': 'What is the Problem Management practice?', 'answer': 'Problem Management reduces the likelihood and impact of incidents by identifying their root causes and managing known errors. It has three phases: problem identification, problem control, and error control.', 'example': 'After multiple login failures occur, problem management investigates and finds a database index issue — fixing the root cause prevents future incidents.'},
      {'order': 5, 'question': 'What is the Service Desk practice?', 'answer': 'The Service Desk is the single point of contact between the service provider and users. It handles incidents, service requests, and communications — acting as the frontline of IT support for the organisation.', 'example': 'A user calls the service desk because their laptop won\'t connect to the VPN — the desk logs the issue, provides a fix, and closes the ticket.'},
      {'order': 6, 'question': 'What is the Continual Improvement practice?', 'answer': 'The Continual Improvement practice aligns services and practices with changing business needs through ongoing identification and improvement of all elements of the SVS. It uses the seven-step Continual Improvement Model to guide improvements.', 'example': 'After reviewing data showing 40% of calls relate to printer issues, the team creates a self-service guide — this is continual improvement in action.'},
    ]);

    await _addQuiz('itil-v4', 'module-6', [
      {'order': 1, 'question': 'How many practices does ITIL V4 define?', 'options': ['14', '26', '34', '42'], 'correctIndex': 2, 'explanation': 'ITIL V4 defines 34 practices across three categories: General Management, Service Management, and Technical Management.'},
      {'order': 2, 'question': 'What is the goal of Incident Management?', 'options': ['To find the root cause of problems', 'To minimise impact and restore normal service as quickly as possible', 'To manage scheduled maintenance', 'To approve changes to IT systems'], 'correctIndex': 1, 'explanation': 'Incident Management aims to restore normal service operation quickly and minimise the negative impact of incidents.'},
