      {'order': 4, 'question': 'What does Problem Management focus on?', 'options': ['Resolving incidents faster', 'Identifying root causes to reduce likelihood of future incidents', 'Managing service requests', 'Monitoring system performance'], 'correctIndex': 1, 'explanation': 'Problem Management identifies root causes of incidents and manages known errors to prevent recurrence.'},
      {'order': 5, 'question': 'What is the Service Desk\'s primary role?', 'options': ['To write IT policies', 'To be the single point of contact between users and the service provider', 'To manage IT budgets', 'To design new services'], 'correctIndex': 1, 'explanation': 'The Service Desk acts as the single point of contact, handling incidents, requests, and communications with users.'},
      {'order': 6, 'question': 'Which practice uses a seven-step model to guide improvements?', 'options': ['Incident Management', 'Service Desk', 'Continual Improvement', 'Change Enablement'], 'correctIndex': 2, 'explanation': 'The Continual Improvement practice uses a seven-step Continual Improvement Model to structure and guide improvement initiatives.'},
    ]);

